sql:
SELECT v.vehicle_id
FROM vehicles v
WHERE v.vehicle_type = 'drone' AND v.owner_id = (SELECT user_id FROM users WHERE user_name = 'John Doe');

SELECT COUNT(vehicle_id) 
FROM sensor_installations 
WHERE installation_method = 'manual';

SELECT DISTINCT u.user_name
FROM users u
INNER JOIN user_access ua ON u.user_id = ua.user_id;

SELECT vehicle_id, COUNT(*) AS total_paths
FROM motion_data
GROUP BY vehicle_id;

